import type { Metadata } from "next";
import VitalsFlowsheet from "./VitalsFlowsheet";

export const metadata: Metadata = {
  title: "バイタルサイン記録 / 温度板 | ぐんじょう 看護記録",
  description:
    "入院患者のバイタルサイン記録・温度板。患者コンテキスト（患者ID / 氏名 / 年齢・性別 / 病棟・病室 / 担当）の上で、体温・血圧（収縮期・拡張期）・脈拍・呼吸・SpO₂・意識レベル（JCS）・測定時刻を入力し、各値を基準値（正常範囲）と照合して 正常 / 高値(H) / 低値(L) / 異常（パニック値）を アイコン＋文字＋トーン で表示。フローシート（時系列グリッド）と温度板（体温・脈拍トレンド）で異常傾向を確認し、異常値は医師報告／再検へ導きます。",
};

export default function VitalsPage() {
  return <VitalsFlowsheet />;
}

// app/vitals/data.ts
// ────────────────────────────────────────────────────────────────────────────
// バイタルサイン記録 / 温度板 — clinical data + reference-range flagging logic.
//
// NOTE (finding): @gunjo/ui ships no reference-range / abnormal-value primitive,
// so the value→flag computation lives here as pure functions and is rendered by
// a hand-rolled <VitalFlag> (Badge + icon + text + tone) in the screen.
// ────────────────────────────────────────────────────────────────────────────

export type VitalKey =
  | "temp"
  | "sysBp"
  | "diaBp"
  | "pulse"
  | "resp"
  | "spo2";

/** A reference (normal) range plus optional panic/critical bounds. */
export interface ReferenceRange {
  /** Lower bound of the normal band (inclusive). */
  low?: number;
  /** Upper bound of the normal band (inclusive). */
  high?: number;
  /** At/below this → critical-low (異常・パニック値). */
  criticalLow?: number;
  /** At/above this → critical-high (異常・パニック値). */
  criticalHigh?: number;
}

export type RangeFlag =
  | "normal"
  | "high"
  | "low"
  | "critical-high"
  | "critical-low";

export type FlagTone = "success" | "warning" | "destructive";

/** Adult reference ranges (sensible defaults). */
export const VITAL_META: Record<
  VitalKey,
  {
    label: string;
    short: string;
    unit: string;
    range: ReferenceRange;
    /** Sensible input bounds (plausibility). */
    min: number;
    max: number;
    step: number;
    decimals: number;
  }
> = {
  temp: {
    label: "体温",
    short: "体温",
    unit: "℃",
    range: { low: 36.0, high: 37.5, criticalLow: 34.9, criticalHigh: 39.9 },
    min: 30,
    max: 43,
    step: 0.1,
    decimals: 1,
  },
  sysBp: {
    label: "収縮期血圧",
    short: "SBP",
    unit: "mmHg",
    range: { low: 90, high: 139, criticalLow: 80, criticalHigh: 180 },
    min: 40,
    max: 280,
    step: 1,
    decimals: 0,
  },
  diaBp: {
    label: "拡張期血圧",
    short: "DBP",
    unit: "mmHg",
    range: { low: 60, high: 89, criticalLow: 40, criticalHigh: 120 },
    min: 20,
    max: 180,
    step: 1,
    decimals: 0,
  },
  pulse: {
    label: "脈拍",
    short: "脈拍",
    unit: "回/分",
    range: { low: 60, high: 100, criticalLow: 40, criticalHigh: 130 },
    min: 20,
    max: 250,
    step: 1,
    decimals: 0,
  },
  resp: {
    label: "呼吸",
    short: "呼吸",
    unit: "回/分",
    range: { low: 12, high: 20, criticalLow: 8, criticalHigh: 30 },
    min: 4,
    max: 60,
    step: 1,
    decimals: 0,
  },
  spo2: {
    label: "SpO₂",
    short: "SpO₂",
    unit: "%",
    range: { low: 96, high: 100, criticalLow: 90, criticalHigh: undefined },
    min: 50,
    max: 100,
    step: 1,
    decimals: 0,
  },
};

/**
 * Pure flag derivation: classify a value against its reference range.
 * critical wins over plain high/low. This is the helper a `flagValue()` export
 * on a real `ReferenceValue` primitive would provide.
 */
export function flagValue(
  value: number | null | undefined,
  range: ReferenceRange
): RangeFlag | null {
  if (value == null || Number.isNaN(value)) return null;
  const { low, high, criticalLow, criticalHigh } = range;
  if (criticalLow != null && value <= criticalLow) return "critical-low";
  if (criticalHigh != null && value >= criticalHigh) return "critical-high";
  if (low != null && value < low) return "low";
  if (high != null && value > high) return "high";
  return "normal";
}

export function flagTone(flag: RangeFlag | null): FlagTone {
  switch (flag) {
    case "high":
    case "low":
      return "warning";
    case "critical-high":
    case "critical-low":
      return "destructive";
    case "normal":
    default:
      return "success";
  }
}

/** Short code shown next to the value (never colour-only). */
export function flagCode(flag: RangeFlag | null): string {
  switch (flag) {
    case "high":
      return "H";
    case "low":
      return "L";
    case "critical-high":
      return "HH";
    case "critical-low":
      return "LL";
    case "normal":
      return "";
    default:
      return "";
  }
}

/** Japanese full text used for the visible label + screen-reader sentence. */
export function flagText(flag: RangeFlag | null): string {
  switch (flag) {
    case "high":
      return "高値";
    case "low":
      return "低値";
    case "critical-high":
      return "異常高値";
    case "critical-low":
      return "異常低値";
    case "normal":
      return "基準値内";
    default:
      return "—";
  }
}

export function isAbnormal(flag: RangeFlag | null): boolean {
  return flag != null && flag !== "normal";
}

export function isCritical(flag: RangeFlag | null): boolean {
  return flag === "critical-high" || flag === "critical-low";
}

/** A recorded vital set at one timestamp. */
export interface VitalSet {
  id: string;
  /** ISO-ish "MM/DD HH:mm" display key + a sortable timestamp. */
  at: number; // epoch ms
  temp: number;
  sysBp: number;
  diaBp: number;
  pulse: number;
  resp: number;
  spo2: number;
  /** 意識レベル — JCS code (e.g. "0", "1", "200"). */
  consciousness: string;
  recordedBy: string;
}

export const patient = {
  id: "P-0098231",
  name: "佐藤 美咲",
  kana: "サトウ ミサキ",
  age: 72,
  sex: "女",
  ward: "東4病棟",
  room: "412号室 2-A",
  nurse: "山田 看護師",
  attending: "鈴木 医師",
};

/** JCS (Japan Coma Scale) options for 意識レベル. */
export const JCS_OPTIONS: { value: string; label: string }[] = [
  { value: "0", label: "0 — 清明" },
  { value: "1", label: "I-1 — 見当識あり/やや不鮮明" },
  { value: "2", label: "I-2 — 見当識障害" },
  { value: "3", label: "I-3 — 名前/生年月日が言えない" },
  { value: "10", label: "II-10 — 呼びかけで開眼" },
  { value: "20", label: "II-20 — 大声/揺さぶりで開眼" },
  { value: "30", label: "II-30 — 痛み刺激で開眼" },
  { value: "100", label: "III-100 — 払いのける" },
  { value: "200", label: "III-200 — 手足を動かす" },
  { value: "300", label: "III-300 — 反応なし" },
];

export function jcsLabel(code: string): string {
  return JCS_OPTIONS.find((o) => o.value === code)?.label ?? code;
}

/** JCS is abnormal when not 0 (清明). 100+ = III group → critical-ish. */
export function jcsFlag(code: string): RangeFlag | null {
  if (code === "" || code == null) return null;
  if (code === "0") return "normal";
  const n = Number(code);
  if (Number.isNaN(n)) return "normal";
  if (n >= 100) return "critical-high";
  return "high";
}

// ── Seed history: last 3 days, ~3 readings/day, with a clear fever trend ──────
const DAY = 24 * 60 * 60 * 1000;
const NOW = new Date("2026-06-23T08:00:00").getTime();

function mk(
  daysAgo: number,
  hour: number,
  temp: number,
  sysBp: number,
  diaBp: number,
  pulse: number,
  resp: number,
  spo2: number,
  consciousness = "0",
  recordedBy = "山田"
): VitalSet {
  const base = NOW - daysAgo * DAY;
  const d = new Date(base);
  d.setHours(hour, 0, 0, 0);
  return {
    id: `vs-${daysAgo}-${hour}`,
    at: d.getTime(),
    temp,
    sysBp,
    diaBp,
    pulse,
    resp,
    spo2,
    consciousness,
    recordedBy,
  };
}

export const seedHistory: VitalSet[] = [
  mk(3, 6, 36.6, 122, 76, 72, 16, 98),
  mk(3, 14, 36.9, 128, 80, 78, 17, 98),
  mk(3, 22, 37.0, 126, 78, 80, 16, 97),
  mk(2, 6, 37.2, 130, 82, 84, 18, 97),
  mk(2, 14, 37.6, 134, 84, 90, 18, 96),
  mk(2, 22, 38.0, 138, 86, 96, 20, 96),
  mk(1, 6, 38.3, 140, 88, 100, 21, 95),
  mk(1, 14, 38.6, 142, 88, 104, 22, 94),
  mk(1, 22, 38.4, 136, 84, 98, 20, 95),
  // today, earlier reading
  mk(0, 6, 38.1, 132, 82, 94, 19, 96, "0", "山田"),
];

/** "MM/DD HH:mm" for display. */
export function fmtAt(epoch: number): string {
  const d = new Date(epoch);
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const dd = String(d.getDate()).padStart(2, "0");
  const hh = String(d.getHours()).padStart(2, "0");
  const mi = String(d.getMinutes()).padStart(2, "0");
  return `${mm}/${dd} ${hh}:${mi}`;
}

/** "HH:mm" only, for compact axis labels. */
export function fmtTime(epoch: number): string {
  const d = new Date(epoch);
  const hh = String(d.getHours()).padStart(2, "0");
  const mi = String(d.getMinutes()).padStart(2, "0");
  return `${hh}:${mi}`;
}

export function fmtVital(value: number, key: VitalKey): string {
  const { decimals } = VITAL_META[key];
  return value.toFixed(decimals);
}

"use client";

import * as React from "react";
import {
  IconActivity,
  IconAlertTriangle,
  IconArrowUp,
  IconArrowDown,
  IconBedFilled,
  IconCheck,
  IconChevronRight,
  IconCircleCheck,
