  TabsTrigger,
} from "@gunjo/ui";

import {
  JCS_OPTIONS,
  VITAL_META,
  type VitalKey,
  type VitalSet,
  type RangeFlag,
  flagValue,
  flagTone,
  flagCode,
  flagText,
  fmtAt,
  fmtTime,
  fmtVital,
  isAbnormal,
  isCritical,
  jcsFlag,
  jcsLabel,
  patient,
  seedHistory,
} from "./data";

// ── Hand-rolled reference-range flag (the medical-specific gap) ──────────────
// @gunjo/ui has no value-vs-range indicator, so this composes Badge + icon +
// text + tone. Never colour-only: icon + H/L/!! code + Japanese word + sr text.

const TONE_BADGE: Record<
  ReturnType<typeof flagTone>,
  "success" | "warning" | "destructive"
> = {
  success: "success",
  warning: "warning",
  destructive: "destructive",
};

function flagIcon(flag: RangeFlag | null): TablerIcon | null {
  switch (flag) {
    case "high":
    case "critical-high":
      return IconArrowUp;
    case "low":
    case "critical-low":
      return IconArrowDown;
    case "normal":
      return IconCheck;
    default:
      return null;
  }
}

/** Inline value + flag, e.g. for a flowsheet cell or a stat. */
function VitalFlag({
  value,
  vitalKey,
  showValue = true,
  size = "sm",
}: {
  value: number | null;
  vitalKey: VitalKey;
  showValue?: boolean;
  size?: "sm" | "md";
}) {
  const meta = VITAL_META[vitalKey];
  const flag = flagValue(value, meta.range);
  const tone = flagTone(flag);
  const code = flagCode(flag);
  const glyph = flagIcon(flag);
  const text = flagText(flag);
  const abnormal = isAbnormal(flag);

  const valueText =
    value == null ? "—" : `${fmtVital(value, vitalKey)}${meta.unit}`;
  const srSentence =
    value == null
      ? `${meta.label} 未測定`
      : `${meta.label} ${fmtVital(value, vitalKey)}${meta.unit}、${text}` +
        (abnormal ? "、要確認" : "");

  return (
    <span className="inline-flex items-center gap-1.5 whitespace-nowrap">
      {showValue ? (
        <span
          className={
            "tabular-nums font-medium " +
            (size === "md" ? "text-base " : "text-sm ") +
            (isCritical(flag)
              ? "text-destructive"
              : abnormal
                ? "text-warning"
                : "text-foreground")
          }
        >
          {valueText}
        </span>
      ) : null}
      {flag && flag !== "normal" ? (
        <Badge
          variant={TONE_BADGE[tone]}
          className="gap-0.5 px-1.5"
          aria-hidden="true"
        >
          {glyph ? <Icon icon={glyph} size="xs" /> : null}
          <span>{code || text}</span>
        </Badge>
      ) : showValue ? null : (
        // normal, value hidden: still show a quiet "基準値内" affordance
        <Badge variant="success" className="gap-0.5 px-1.5" aria-hidden="true">
          <Icon icon={IconCheck} size="xs" />
          <span>正常</span>
        </Badge>
      )}
      <span className="sr-only">{srSentence}</span>
    </span>
  );
}

// ── Form field with a live flag preview ──────────────────────────────────────
interface VitalInputFieldProps {
  vitalKey: VitalKey;
  value: number | null;
  onChange: (v: number | null) => void;
  icon: TablerIcon;
  invalid?: boolean;
  errorId?: string;
  errorText?: string;
}

function VitalInputField({
  vitalKey,
  value,
  onChange,
  icon,
  invalid,
  errorId,
  errorText,
}: VitalInputFieldProps) {
  const meta = VITAL_META[vitalKey];
  const id = `vital-${vitalKey}`;
  const flag = value != null ? flagValue(value, meta.range) : null;
  const abnormal = isAbnormal(flag);

  return (
    <div className="flex flex-col gap-1.5">
      <Label htmlFor={id} className="flex items-center gap-1.5">
        <Icon icon={icon} size="sm" className="text-muted-foreground" />
        <span>{meta.label}</span>
        <span className="text-xs font-normal text-muted-foreground">
          ({meta.unit})
        </span>
      </Label>
      <div className="flex items-center gap-2">
        <NumberInput
          id={id}
          value={value ?? undefined}
          onValueChange={(v) => onChange(Number.isNaN(v) ? null : v)}
          min={meta.min}
          max={meta.max}
          step={meta.step}
          aria-label={`${meta.label}（${meta.unit}）`}
          aria-invalid={invalid || undefined}
          aria-describedby={
            [errorId, `${id}-ref`].filter(Boolean).join(" ") || undefined
          }
          className="flex-1"
        />
        <span className="min-w-[3.5rem] shrink-0">
          {value != null && flag ? (
            <VitalFlag value={value} vitalKey={vitalKey} showValue={false} />
          ) : (
            <span className="text-xs text-muted-foreground">—</span>
          )}
        </span>
      </div>
      <p id={`${id}-ref`} className="text-xs text-muted-foreground">
        基準値 {meta.range.low ?? "–"}
        {meta.range.high != null ? `–${meta.range.high}` : "+"} {meta.unit}
        {abnormal ? (
          <span className="ml-1 font-medium text-warning">
            · {flagText(flag)}
          </span>
        ) : null}
      </p>
      {invalid && errorText ? (
        <p id={errorId} className="text-xs font-medium text-destructive">
          {errorText}
        </p>
      ) : null}
    </div>
  );
}

// ── Trend chart (温度板) — LineChart per series + hand-rolled normal band ─────
// @gunjo/ui LineChart supports a single referenceValue *line*, not a shaded
// *band*, and one shared Y domain — so 体温 / 脈拍 are rendered as two stacked
// charts (own domain each) with the normal band as a CSS overlay behind each.

function TrendChart({
  title,
  series,
  labels,
  domainMin,
  domainMax,
  band,
  unit,
  color,
  formatValue,
  icon,
}: {
  title: string;
  series: number[];
  labels: string[];
  domainMin: number;
  domainMax: number;
  band: { from: number; to: number };
  unit: string;
  color: "primary" | "destructive" | "warning" | "success" | "info" | "muted";
  formatValue: (v: number) => string;
  icon: TablerIcon;
}) {
  // Band overlay position as % of the plotted height (top = domainMax).
  const span = domainMax - domainMin || 1;
  const topPct = ((domainMax - band.to) / span) * 100;
  const heightPct = ((band.to - band.from) / span) * 100;

  return (
    <div>
      <div className="mb-1 flex items-center justify-between gap-2">
        <h4 className="flex items-center gap-1.5 text-sm font-medium">
          <Icon icon={icon} size="sm" className="text-muted-foreground" />
          {title}
        </h4>
        <span className="text-xs text-muted-foreground">
          基準帯 {band.from}–{band.to} {unit}
        </span>
      </div>
      <div className="relative">
        {/* Hand-rolled shaded normal band (LineChart can't render a band). */}
        <div
          aria-hidden="true"
          className="pointer-events-none absolute inset-x-0 z-0 rounded-sm bg-success/10"
          style={{
            top: `calc(14px + ${topPct}% * (260px - 24px) / 260)`,
            height: `calc(${heightPct}% * (260px - 24px) / 260)`,
          }}
        />
        <div className="relative z-10">
          <LineChart
            series={[{ label: title, data: series, color }]}
            min={domainMin}
            max={domainMax}
            referenceValue={band.to}
            referenceLabel={`上限 ${band.to}`}
            showGrid
            showDots
            showLabels={false}
            showLegend={false}
            formatValue={(v) => formatValue(v)}
            aria-hidden="true"
          />
        </div>
      </div>
      <div className="mt-1 flex justify-between px-1 text-[10px] text-muted-foreground">
        {labels.map((l, i) => (
          <span key={i} className="tabular-nums">
            {l}
          </span>
        ))}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────

const FLOWSHEET_KEYS: VitalKey[] = [
  "temp",
  "sysBp",
  "diaBp",
  "pulse",
  "resp",
  "spo2",
];

const ROW_ICON: Record<VitalKey, TablerIcon> = {
  temp: IconTemperature,
  sysBp: IconActivity,
  diaBp: IconActivity,
  pulse: IconHeartbeat,
  resp: IconLungs,
  spo2: IconWind,
};

type Draft = Record<VitalKey, number | null> & { consciousness: string };

const emptyDraft: Draft = {
  temp: null,
  sysBp: null,
  diaBp: null,
  pulse: null,
  resp: null,
  spo2: null,
  consciousness: "0",
};

export default function VitalsFlowsheet() {
  const [history, setHistory] = React.useState<VitalSet[]>(seedHistory);
  const [draft, setDraft] = React.useState<Draft>(emptyDraft);
  const [measuredAt, setMeasuredAt] = React.useState("08:00");
  const [touched, setTouched] = React.useState(false);
  const [confirmOpen, setConfirmOpen] = React.useState(false);
  const [savedSet, setSavedSet] = React.useState<VitalSet | null>(null);

  const setField = (k: VitalKey, v: number | null) => {
    setDraft((d) => ({ ...d, [k]: v }));
    setSavedSet(null);
  };

  // Sorted newest→oldest for display.
  const sorted = React.useMemo(
    () => [...history].sort((a, b) => b.at - a.at),
    [history]
  );
  const latest = sorted[0];
  const previous = sorted[1];

  // Live abnormal detection on the draft being entered.
  const draftFlags = React.useMemo(() => {
    const out: { key: VitalKey; flag: RangeFlag | null }[] = [];
    for (const k of FLOWSHEET_KEYS) {
      const v = draft[k];
      out.push({ key: k, flag: v != null ? flagValue(v, VITAL_META[k].range) : null });
    }
    return out;
  }, [draft]);

  const jcsDraftFlag = jcsFlag(draft.consciousness);
  const abnormalDraft = draftFlags.filter((f) => isAbnormal(f.flag));
  const criticalDraft = draftFlags.filter((f) => isCritical(f.flag));
  const hasJcsAbnormal = jcsDraftFlag != null && jcsDraftFlag !== "normal";

  // Validation: all six vitals required + plausibility (NumberInput clamps, but
  // we also guard explicitly so empties are caught).
  const requiredMissing = FLOWSHEET_KEYS.filter((k) => draft[k] == null);
  const isValid = requiredMissing.length === 0 && /^\d{2}:\d{2}$/.test(measuredAt);

  const handleSaveClick = () => {
    setTouched(true);
    if (!isValid) return;
    setConfirmOpen(true);
  };

  const commitSave = () => {
    const [hh, mi] = measuredAt.split(":").map(Number);
    const d = new Date();
    d.setHours(hh, mi, 0, 0);
    const newSet: VitalSet = {
      id: `vs-new-${Date.now()}`,
      at: d.getTime(),
      temp: draft.temp as number,
      sysBp: draft.sysBp as number,
      diaBp: draft.diaBp as number,
      pulse: draft.pulse as number,
      resp: draft.resp as number,
      spo2: draft.spo2 as number,
      consciousness: draft.consciousness,
      recordedBy: patient.nurse.split(" ")[0],
    };
    setHistory((h) => [...h, newSet]);
    setSavedSet(newSet);
    setConfirmOpen(false);
    setDraft(emptyDraft);
    setTouched(false);
  };

  const resetDraft = () => {
    setDraft(emptyDraft);
    setTouched(false);
    setSavedSet(null);
  };

  // ── 温度板 series (oldest→newest, last ~10 readings) ──
  const chronological = React.useMemo(
    () => [...history].sort((a, b) => a.at - b.at).slice(-10),
    [history]
  );
  const tempSeries = chronological.map((s) => s.temp);
  const pulseSeries = chronological.map((s) => s.pulse);
  const chartLabels = chronological
    .filter((_, i) => i % 2 === 0)
    .map((s) => fmtTime(s.at));

  return (
    <main className="mx-auto w-full max-w-6xl px-4 py-6 sm:px-6 lg:py-8">
      {/* live region for abnormal/critical announcements */}
      <div aria-live="assertive" className="sr-only" role="status">
        {savedSet
          ? `バイタルを記録しました。${fmtAt(savedSet.at)}。`
          : criticalDraft.length > 0
            ? `異常値を検知。${criticalDraft
                .map((f) => `${VITAL_META[f.key].label}が${flagText(f.flag)}`)
                .join("、")}。医師報告を検討してください。`
            : abnormalDraft.length > 0
              ? `基準値外の値があります。${abnormalDraft
                  .map((f) => `${VITAL_META[f.key].label}が${flagText(f.flag)}`)
                  .join("、")}。`
              : ""}
      </div>

      <h1 className="text-2xl font-bold tracking-tight">
        バイタルサイン記録 / 温度板
      </h1>
      <p className="mt-1 text-sm text-muted-foreground">
        測定値を入力すると基準値と照合し、高値(H) / 低値(L) / 異常を自動でフラグします。
      </p>

      {/* ── 患者コンテキスト ─────────────────────────────────────────── */}
      <Card className="mt-4">
        <CardContent className="flex flex-col gap-3 p-4 sm:flex-row sm:flex-wrap sm:items-center sm:gap-x-6 sm:gap-y-2">
          <div className="flex items-center gap-3">
            <span className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-secondary">
              <Icon icon={IconUser} size="md" className="text-muted-foreground" />
            </span>
            <div>
              <p className="flex items-center gap-2 text-base font-semibold">
                {patient.name}
                <span className="text-xs font-normal text-muted-foreground">
                  {patient.kana}
                </span>
              </p>
              <p className="text-xs text-muted-foreground">
                ID {patient.id} · {patient.age}歳 · {patient.sex}
              </p>
            </div>
          </div>
          <Separator className="sm:hidden" />
          <dl className="flex flex-wrap gap-x-6 gap-y-1 text-sm">
            <div className="flex items-center gap-1.5">
              <Icon icon={IconBedFilled} size="sm" className="text-muted-foreground" />
              <dt className="sr-only">病棟・病室</dt>
              <dd>
                {patient.ward} · {patient.room}
              </dd>
            </div>
            <div className="flex items-center gap-1.5">
              <Icon icon={IconStethoscope} size="sm" className="text-muted-foreground" />
              <dt className="sr-only">担当</dt>
              <dd>
                担当 {patient.nurse} / 主治医 {patient.attending}
              </dd>
            </div>
          </dl>
        </CardContent>
      </Card>

      <div className="mt-4 grid grid-cols-1 gap-4 lg:grid-cols-[minmax(0,420px)_minmax(0,1fr)]">
        {/* ── バイタル入力 ─────────────────────────────────────────── */}
        <Card className="self-start">
          <CardHeader className="pb-3">
            <CardTitle as="h2" className="flex items-center gap-2 text-lg">
              <Icon icon={IconClockHour4} size="sm" />
              新規バイタル記録
            </CardTitle>
            <CardDescription>
              測定時刻と各項目を入力してください。全項目必須。
            </CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col gap-4">
            {/* saved confirmation */}
            {savedSet ? (
              <Alert variant="success">
                <Icon icon={IconCircleCheck} size="sm" decorative />
                <AlertTitle as="h3">記録しました</AlertTitle>
                <AlertDescription>
                  {fmtAt(savedSet.at)} のバイタルをフローシートと温度板に反映しました。
                </AlertDescription>
              </Alert>
            ) : null}

            {/* 測定時刻 */}
            <div className="flex flex-col gap-1.5">
              <Label htmlFor="measured-at" className="flex items-center gap-1.5">
                <Icon icon={IconClockHour4} size="sm" className="text-muted-foreground" />
                測定時刻
              </Label>
              <input
                id="measured-at"
                type="time"
                value={measuredAt}
                onChange={(e) => setMeasuredAt(e.target.value)}
                className="inline-flex h-9 w-full items-center rounded-lg border border-input bg-transparent px-3 py-2 text-sm shadow-sm focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
              />
            </div>

            <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
              <VitalInputField
                vitalKey="temp"
                value={draft.temp}
                onChange={(v) => setField("temp", v)}
                icon={IconTemperature}
                invalid={touched && draft.temp == null}
                errorId="temp-err"
                errorText="体温を入力してください"
              />
              <VitalInputField
                vitalKey="pulse"
                value={draft.pulse}
                onChange={(v) => setField("pulse", v)}
                icon={IconHeartbeat}
                invalid={touched && draft.pulse == null}
                errorId="pulse-err"
                errorText="脈拍を入力してください"
              />
              <VitalInputField
                vitalKey="sysBp"
                value={draft.sysBp}
                onChange={(v) => setField("sysBp", v)}
                icon={IconActivity}
                invalid={touched && draft.sysBp == null}
                errorId="sys-err"
                errorText="収縮期血圧を入力してください"
              />
              <VitalInputField
                vitalKey="diaBp"
                value={draft.diaBp}
                onChange={(v) => setField("diaBp", v)}
                icon={IconActivity}
                invalid={touched && draft.diaBp == null}
                errorId="dia-err"
                errorText="拡張期血圧を入力してください"
              />
              <VitalInputField
                vitalKey="resp"
                value={draft.resp}
                onChange={(v) => setField("resp", v)}
                icon={IconLungs}
                invalid={touched && draft.resp == null}
                errorId="resp-err"
                errorText="呼吸を入力してください"
              />
              <VitalInputField
                vitalKey="spo2"
                value={draft.spo2}
                onChange={(v) => setField("spo2", v)}
                icon={IconWind}
                invalid={touched && draft.spo2 == null}
                errorId="spo2-err"
                errorText="SpO₂を入力してください"
              />
            </div>

            {/* 意識レベル */}
            <div className="flex flex-col gap-1.5">
              <Select
                label="意識レベル (JCS)"
                value={draft.consciousness}
                onChange={(e) => {
                  setDraft((d) => ({ ...d, consciousness: e.target.value }));
                  setSavedSet(null);
                }}
              >
                {JCS_OPTIONS.map((o) => (
                  <option key={o.value} value={o.value}>
                    {o.label}
                  </option>
                ))}
              </Select>
              {hasJcsAbnormal ? (
                <p className="flex items-center gap-1 text-xs font-medium text-warning">
                  <Icon icon={IconAlertTriangle} size="xs" />
                  意識レベルの低下に注意（清明=0 以外）
                </p>
              ) : null}
            </div>

            {/* live abnormal summary in the form */}
            {touched && requiredMissing.length > 0 ? (
              <Alert variant="warning">
                <Icon icon={IconAlertTriangle} size="sm" decorative />
                <AlertTitle as="h3">未入力の項目があります</AlertTitle>
                <AlertDescription>
                  {requiredMissing
                    .map((k) => VITAL_META[k].label)
                    .join("、")}{" "}
                  を入力してください。
                </AlertDescription>
              </Alert>
            ) : null}

            {criticalDraft.length > 0 ? (
              <Alert variant="destructive">
                <Icon icon={IconAlertTriangle} size="sm" decorative />
                <AlertTitle as="h3">異常値（パニック値）を検知</AlertTitle>
                <AlertDescription>
                  {criticalDraft
                    .map(
                      (f) =>
                        `${VITAL_META[f.key].label} ${fmtVital(
                          draft[f.key] as number,
                          f.key
                        )}${VITAL_META[f.key].unit}（${flagText(f.flag)}）`
                    )
                    .join("、")}
                  。記録後、医師報告／再検を行ってください。
                </AlertDescription>
              </Alert>
            ) : abnormalDraft.length > 0 ? (
              <Alert variant="warning">
                <Icon icon={IconAlertTriangle} size="sm" decorative />
                <AlertTitle as="h3">基準値外の値があります</AlertTitle>
                <AlertDescription>
                  {abnormalDraft
                    .map(
                      (f) =>
                        `${VITAL_META[f.key].label}（${flagText(f.flag)}）`
                    )
                    .join("、")}
                  。確認のうえ記録してください。
                </AlertDescription>
              </Alert>
            ) : null}

            <div className="flex flex-wrap gap-2">
              <Button
                variant={criticalDraft.length > 0 ? "destructive" : "primary"}
                onClick={handleSaveClick}
                className="flex-1"
              >
                <Icon icon={IconDeviceFloppy} size="sm" decorative />
                記録する
              </Button>
              <Button variant="outline" onClick={resetDraft}>
                <Icon icon={IconRefresh} size="sm" decorative />
                クリア
              </Button>
            </div>
            {criticalDraft.length > 0 ? (
              <Button variant="outline" className="w-full" asChild>
                <a href="#report">
                  <Icon icon={IconPhoneCall} size="sm" decorative />
                  医師に報告 / 再検を依頼
                </a>
              </Button>
            ) : null}
          </CardContent>
        </Card>

        {/* ── 最新サマリ + フローシート + 温度板 ─────────────────────── */}
        <div className="flex flex-col gap-4">
          {/* latest snapshot with deltas vs previous */}
          <Card>
            <CardHeader className="pb-3">
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <IconActivity className="h-5 w-5" aria-hidden="true" />
                最新バイタル
                {latest ? (
                  <span className="text-sm font-normal text-muted-foreground">
                    {fmtAt(latest.at)} · {latest.recordedBy}
                  </span>
                ) : null}
              </CardTitle>
            </CardHeader>
            <CardContent>
              {latest ? (
                <ul className="grid grid-cols-2 gap-x-4 gap-y-3 sm:grid-cols-3">
                  {FLOWSHEET_KEYS.map((k) => {
                    const prevVal = previous ? previous[k] : undefined;
                    const change =
                      prevVal != null ? latest[k] - prevVal : null;
                    return (
                      <li key={k} className="flex flex-col gap-0.5">
                        <span className="flex items-center gap-1 text-xs text-muted-foreground">
                          <Icon
                            icon={ROW_ICON[k]}
                            size="xs"
                            className="text-muted-foreground"
                          />
                          {VITAL_META[k].label}
                        </span>
                        <VitalFlag value={latest[k]} vitalKey={k} size="md" />
                        {change != null && change !== 0 ? (
                          <Delta
                            value={Number(change.toFixed(VITAL_META[k].decimals))}
                            format={(v) =>
                              `${v > 0 ? "+" : ""}${v.toFixed(
                                VITAL_META[k].decimals
                              )}`
                            }
                            // A vital "up" isn't inherently good/bad → neutral tones,
                            // change is informational only. Range flag carries meaning.
                            tones={{
                              positive: "muted",
                              negative: "muted",
                              zero: "muted",
                            }}
                            labels={{
                              positive: "前回比 増加",
                              negative: "前回比 減少",
                            }}
                            className="text-xs"
                          />
                        ) : (
                          <span className="text-xs text-muted-foreground">
                            前回比 ±0
                          </span>
                        )}
                      </li>
                    );
                  })}
                  <li className="flex flex-col gap-0.5">
                    <span className="text-xs text-muted-foreground">意識 (JCS)</span>
                    <span className="inline-flex items-center gap-1.5">
                      <span className="text-base font-medium tabular-nums">
                        {latest.consciousness}
                      </span>
                      {jcsFlag(latest.consciousness) &&
                      jcsFlag(latest.consciousness) !== "normal" ? (
                        <Badge variant="warning" className="px-1.5">
                          要注意
                        </Badge>
                      ) : (
                        <Badge variant="success" className="px-1.5">
                          清明
                        </Badge>
                      )}
                    </span>
                    <span className="text-xs text-muted-foreground">
                      {jcsLabel(latest.consciousness)}
                    </span>
                  </li>
                </ul>
              ) : (
                <p className="text-sm text-muted-foreground">記録がありません。</p>
              )}
            </CardContent>
          </Card>

          {/* tabs: flowsheet / 温度板 */}
          <Card>
            <CardContent className="p-4">
              <Tabs defaultValue="flowsheet">
                <TabsList className="mb-4">
                  <TabsTrigger value="flowsheet">フローシート</TabsTrigger>
                  <TabsTrigger value="chart">温度板</TabsTrigger>
                </TabsList>

                {/* ── フローシート (time-grid) ── */}
                <TabsContent value="flowsheet">
                  <h3 className="sr-only">バイタルサイン フローシート</h3>
                  <div className="overflow-x-auto">
                    <Table className="min-w-[640px]">
                      <caption className="sr-only">
                        直近の測定セット。各値は基準値と照合し H（高値）/ L（低値）/
                        異常 を表示。
                      </caption>
                      <TableHeader>
                        <TableRow>
                          <TableHead scope="col" className="sticky left-0 bg-card">
                            項目
                          </TableHead>
                          {sorted.slice(0, 6).map((s) => (
                            <TableHead
                              key={s.id}
                              scope="col"
                              className="whitespace-nowrap text-right tabular-nums"
                            >
                              {fmtAt(s.at)}
                            </TableHead>
                          ))}
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {FLOWSHEET_KEYS.map((k) => (
                          <TableRow key={k}>
                            <TableHead
                              scope="row"
                              className="sticky left-0 bg-card whitespace-nowrap font-medium"
                            >
                              <span className="flex items-center gap-1.5">
                                <Icon
                                  icon={ROW_ICON[k]}
                                  size="xs"
                                  className="text-muted-foreground"
                                />
                                {VITAL_META[k].label}
                                <span className="text-xs font-normal text-muted-foreground">
                                  {VITAL_META[k].unit}
                                </span>
                              </span>
                            </TableHead>
                            {sorted.slice(0, 6).map((s) => (
                              <TableCell key={s.id} className="text-right">
                                <VitalFlag value={s[k]} vitalKey={k} />
                              </TableCell>
                            ))}
                          </TableRow>
                        ))}
                        <TableRow>
                          <TableHead
                            scope="row"
                            className="sticky left-0 bg-card whitespace-nowrap font-medium"
                          >
                            意識 (JCS)
                          </TableHead>
                          {sorted.slice(0, 6).map((s) => {
                            const f = jcsFlag(s.consciousness);
                            const abn = f != null && f !== "normal";
                            return (
                              <TableCell key={s.id} className="text-right">
                                <span className="inline-flex items-center gap-1.5">
                                  <span className="tabular-nums">
                                    {s.consciousness}
                                  </span>
                                  {abn ? (
                                    <Badge variant="warning" className="px-1.5">
                                      要注意
                                    </Badge>
                                  ) : null}
                                </span>
                              </TableCell>
                            );
                          })}
                        </TableRow>
                      </TableBody>
                    </Table>
                  </div>
                  <p className="mt-2 flex flex-wrap items-center gap-x-3 gap-y-1 text-xs text-muted-foreground">
                    <span className="flex items-center gap-1">
                      <Badge variant="warning" className="px-1.5">
                        H / L
                      </Badge>
                      高値 / 低値
                    </span>
                    <span className="flex items-center gap-1">
                      <Badge variant="destructive" className="px-1.5">
                        HH / LL
                      </Badge>
                      異常（パニック値）
                    </span>
                  </p>
                </TabsContent>

                {/* ── 温度板 (trend) ── */}
                <TabsContent value="chart">
                  <h3 className="sr-only">温度板（体温・脈拍トレンド）</h3>
                  <div className="flex flex-col gap-5">
                    <TrendChart
                      title="体温"
                      icon={IconTemperature}
                      series={tempSeries}
                      labels={chartLabels}
                      domainMin={35}
                      domainMax={40}
                      band={{ from: 36.0, to: 37.5 }}
                      unit="℃"
                      color="destructive"
                      formatValue={(v) => v.toFixed(1)}
                    />
                    <TrendChart
                      title="脈拍"
                      icon={IconHeartbeat}
                      series={pulseSeries}
                      labels={chartLabels}
                      domainMin={50}
                      domainMax={130}
                      band={{ from: 60, to: 100 }}
                      unit="回/分"
                      color="info"
                      formatValue={(v) => v.toFixed(0)}
                    />
                  </div>
                  <p className="mt-3 text-xs text-muted-foreground">
                    淡い帯は基準範囲、点線は基準上限。グラフの数値は下の表でも確認できます。
                  </p>
                  {/* accessible text alternative to the chart */}
                  <details className="mt-2">
                    <summary className="cursor-pointer text-xs font-medium text-foreground">
                      温度板のデータ（表）を表示
                    </summary>
                    <div className="mt-2 overflow-x-auto">
                      <Table className="min-w-[480px]">
                        <caption className="sr-only">
                          温度板のデータ表。測定時刻ごとの体温と脈拍。
                        </caption>
                        <TableHeader>
                          <TableRow>
                            <TableHead scope="col">時刻</TableHead>
                            <TableHead scope="col" className="text-right">
                              体温 (℃)
                            </TableHead>
                            <TableHead scope="col" className="text-right">
                              脈拍 (回/分)
                            </TableHead>
                          </TableRow>
                        </TableHeader>
                        <TableBody>
                          {chronological.map((s) => (
                            <TableRow key={s.id}>
                              <TableHead scope="row" className="whitespace-nowrap">
                                {fmtAt(s.at)}
                              </TableHead>
                              <TableCell className="text-right">
                                <VitalFlag value={s.temp} vitalKey="temp" />
                              </TableCell>
                              <TableCell className="text-right">
                                <VitalFlag value={s.pulse} vitalKey="pulse" />
                              </TableCell>
                            </TableRow>
                          ))}
                        </TableBody>
                      </Table>
                    </div>
                  </details>
                </TabsContent>
              </Tabs>
            </CardContent>
          </Card>

          {/* abnormal-value path / 医師報告 */}
          <Card id="report">
            <CardHeader className="pb-2">
              <CardTitle as="h2" className="flex items-center gap-2 text-base">
                <Icon icon={IconPhoneCall} size="sm" />
                異常値時のアクション
              </CardTitle>
            </CardHeader>
            <CardContent className="flex flex-col gap-2 text-sm text-muted-foreground">
              <p>
                異常値（パニック値）検知時は、記録後すみやかに医師報告・再検を行ってください。
              </p>
              <div className="flex flex-wrap gap-2">
                <Button variant="warning" size="sm">
                  <Icon icon={IconRefresh} size="xs" decorative />
                  再測定を指示
                </Button>
                <Button variant="destructive" size="sm">
                  <Icon icon={IconPhoneCall} size="xs" decorative />
                  医師へ報告
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>

      {/* ── 記録確認ダイアログ ─────────────────────────────────────── */}
      <Dialog open={confirmOpen} onOpenChange={setConfirmOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>バイタルを記録しますか？</DialogTitle>
            <DialogDescription>
              {patient.name} さん · 測定時刻 {measuredAt}
            </DialogDescription>
          </DialogHeader>
          <ul className="flex flex-col gap-1.5 text-sm">
            {FLOWSHEET_KEYS.map((k) => (
              <li key={k} className="flex items-center justify-between gap-2">
                <span className="text-muted-foreground">{VITAL_META[k].label}</span>
                <VitalFlag value={draft[k]} vitalKey={k} />
              </li>
            ))}
            <li className="flex items-center justify-between gap-2">
              <span className="text-muted-foreground">意識 (JCS)</span>
              <span className="tabular-nums">{draft.consciousness}</span>
            </li>
          </ul>
          {criticalDraft.length > 0 ? (
            <Alert variant="destructive">
              <Icon icon={IconAlertTriangle} size="sm" decorative />
              <AlertTitle as="h3">異常値を含みます</AlertTitle>
              <AlertDescription>
                記録後、医師報告／再検を忘れずに行ってください。
              </AlertDescription>
            </Alert>
          ) : null}
          <DialogFooter>
            <Button variant="outline" onClick={() => setConfirmOpen(false)}>
              キャンセル
            </Button>
            <Button
              variant={criticalDraft.length > 0 ? "destructive" : "primary"}
              onClick={commitSave}
            >
              <Icon icon={IconCheck} size="sm" decorative />
              記録を確定
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  );
}
